diff --git a/packages/svelte/src/internal/client/reactivity/deriveds.js b/packages/svelte/src/internal/client/reactivity/deriveds.js
index 7f730e365..b33fe6936 100644
--- a/packages/svelte/src/internal/client/reactivity/deriveds.js
+++ b/packages/svelte/src/internal/client/reactivity/deriveds.js
@@ -315,7 +315,7 @@ export function execute_derived(derived) {
 		try {
 			destroy_derived_effects(derived);
 			value = update_reaction(derived);
-		} finally {
+		} finally{
 			set_active_effect(prev_active_effect);
 		}
 	}
diff --git a/packages/svelte/src/internal/client/runtime.js b/packages/svelte/src/internal/client/runtime.js
index e86866af2..0e487c9ce 100644
--- a/packages/svelte/src/internal/client/runtime.js
+++ b/packages/svelte/src/internal/client/runtime.js
@@ -409,8 +409,10 @@ function remove_reaction(signal, dependency) {
 		if ((dependency.f & (UNOWNED | DISCONNECTED)) === 0) {
 			dependency.f ^= DISCONNECTED;
 		}
-		// Disconnect any reactions owned by this reaction
-		destroy_derived_effects(/** @type {Derived} **/ (dependency));
+		// Don't destroy derived effects here - they should persist as long as the derived exists.
+		// destroying them breaks reactivity for effects created inside the derived (e.g., by createSubscriber)
+		// when the derived is temporarily disconnected and then reconnected.
+		// destroy_derived_effects(/** @type {Derived} **/ (dependency));
 		remove_reactions(/** @type {Derived} **/ (dependency), 0);
 	}
 }
