import { describe, assert, it } from 'vitest';
import { flushSync } from './packages/svelte/src/index-client.js';
import * as $ from './packages/svelte/src/internal/client/runtime.js';
import { push, pop } from './packages/svelte/src/internal/client/context.js';
import {
	effect,
	effect_root,
	render_effect
} from './packages/svelte/src/internal/client/reactivity/effects.js';
import { state, set } from './packages/svelte/src/internal/client/reactivity/sources.js';
import { derived } from './packages/svelte/src/internal/client/reactivity/deriveds.js';
import { createSubscriber } from './packages/svelte/src/reactivity/create-subscriber.js';

function run_test(runes, fn) {
	return () => {
		// Create a component context to test runes vs legacy mode
		push({}, runes);
		// Create a render context so that effect validations etc don't fail
		let execute;
		const destroy = effect_root(() => {
			execute = fn(runes);
		});
		pop();
		execute();
		destroy();
	};
}

function test(text, fn) {
	it(`${text} (legacy mode)`, run_test(false, fn));
	it(`${text} (runes mode)`, run_test(true, fn));
}

describe('createSubscriber with $derived', () => {
	test('createSubscriber reactivity after teardown with derived', () => {
		const log = [];

		// Create a store-like object
		let value = 0;
		let listeners = [];
		const store = {
			subscribe(callback) {
				listeners.push(callback);
				callback(value);
				return () => {
					listeners = listeners.filter(l => l !== callback);
				};
			},
			set(v) {
				value = v;
				listeners.forEach(l => l(v));
			}
		};

		const subscribe = createSubscriber((update) => {
			log.push('subscribe start');
			const unsubscribe = store.subscribe(update);
			return () => {
				log.push('subscribe teardown');
				unsubscribe();
			};
		});

		let show = state(true);

		// Create a derived that uses the subscriber
		let current = derived(() => {
			subscribe();
			return store.subscribe ? value : 0;
		});

		return () => {
			// First effect - should subscribe
			let cleanup1;
			effect(() => {
				if ($.get(show)) {
					const val = $.get(current);
					log.push(`effect1: ${val}`);
				}
			});

			flushSync();

			// Hide - should teardown
			flushSync(() => set(show, false));

			// Show again - should re-subscribe
			flushSync(() => set(show, true));

			// Update store - should trigger effect
			flushSync(() => store.set(1));

			// Check logs
			console.log('Logs:', log);

			// Should see effect1 reacting to store update after re-subscribe
			assert.ok(log.includes('effect1: 1'), 'Effect should see updated value');
		};
	});

	test('createSubscriber reactivity with derived after async update', () => {
		const log = [];

		// Create a store-like object
		let value = 0;
		let listeners = [];
		const store = {
			subscribe(callback) {
				listeners.push(callback);
				callback(value);
				return () => {
					listeners = listeners.filter(l => l !== callback);
				};
			},
			set(v) {
				value = v;
				listeners.forEach(l => l(v));
			}
		};

		const subscribe = createSubscriber((update) => {
			const unsubscribe = store.subscribe(update);
			return () => {
				unsubscribe();
			};
		});

		// Create a derived that uses the subscriber
		let current = derived(() => {
			subscribe();
			return value;
		});

		let condition = state(true);

		return () => {
			// Effect that uses derived
			effect(() => {
				if ($.get(condition)) {
					const val = $.get(current);
					log.push(`value: ${val}`);
				}
			});

			flushSync();
			assert.deepEqual(log, ['value: 0']);

			// Toggle off then on
			flushSync(() => set(condition, false));
			flushSync(() => set(condition, true));

			// Update store asynchronously
			setTimeout(() => {
				store.set(1);
				flushSync();

				// Should see the update
				console.log('Logs after async update:', log);
				assert.ok(log.includes('value: 1'), 'Should see updated value after async store update');
			}, 0);
		};
	});
});

