import * as $ from './packages/svelte/src/internal/client/runtime.js';
import { flushSync } from './packages/svelte/src/index-client.js';

// Create a component context to test
push({}, true);

let cleanup;
let root_effect;
effect_root((e) => {
	root_effect = e;
	const log = [];

	// Create a store-like object
	let value = 0;
	let listeners = [];
	const store = {
		subscribe(callback) {
			listeners.push(callback);
			callback(value);
			return () => {
				listeners = listeners.filter(l => l !== callback);
			};
		},
		set(v) {
			value = v;
			listeners.forEach(l => l(v));
		}
	};

	const subscribe = createSubscriber((update) => {
		const unsubscribe = store.subscribe(update);
		return () => {
			unsubscribe();
		};
	});

	let show = state(true);

	// Create a derived that uses the subscriber
	console.log('Creating derived, active_effect:', $.active_effect === root_effect ? 'root_effect' : 'other');
	let current = derived(() => {
		subscribe();
		return value;
	});
	console.log('Derived created, parent:', current.parent === root_effect ? 'root_effect' : 'other');

	// First effect - should subscribe
	let user_effect_obj;
	user_effect_obj = effect(() => {
		if ($.get(show)) {
			const val = $.get(current);
		}
	});

	flushSync();
	console.log('\n=== After initial setup ===');
	console.log('derived.effects:', current.effects?.length || 0);
	if (current.effects && current.effects.length > 0) {
		const render_eff = current.effects[0];
		console.log('render_effect parent:', render_eff.parent === root_effect ? 'root_effect' : (render_eff.parent === user_effect_obj ? 'user_effect' : 'other'));
	}

	// Hide - should teardown
	flushSync(() => set(show, false));
	console.log('\n=== After hide ===');
	console.log('derived.effects:', current.effects?.length || 0);

	// Show again - should re-subscribe
	flushSync(() => set(show, true));
	console.log('\n=== After show again ===');
	console.log('derived.effects:', current.effects?.length || 0);

	// Update store - should trigger effect
	flushSync(() => store.set(1));
	console.log('\n=== After store update ===');
	console.log('Store has listeners:', listeners.length);

	cleanup = () => {};
});

pop();

