cat > /testbed/final_test.js << 'EOF'
import { createSubscriber } from './packages/svelte/src/reactivity/create-subscriber.js';
import { derived } from './packages/svelte/src/internal/client/reactivity/deriveds.js';
import { state, set } from './packages/svelte/src/internal/client/reactivity/sources.js';
import { effect, effect_root } from './packages/svelte/src/internal/client/reactivity/effects.js';
import { push, pop } from './packages/svelte/src/internal/client/context.js';
import * as $ from './packages/svelte/src/internal/client/runtime.js';
import { flushSync } from './packages/svelte/src/index-client.js';

console.log('Testing the fix for createSubscriber + derived reactivity bug...\n');

push({}, true);

let test_passed = true;

effect_root(() => {
	// Create a store-like object
	let value = 0;
	let listeners = [];
	const store = {
		subscribe(callback) {
			listeners.push(callback);
			callback(value);
			return () => {
				listeners = listeners.filter(l => l !== callback);
			};
		},
		set(v) {
			value = v;
			listeners.forEach(l => l(v));
		}
	};

	const subscribe = createSubscriber((update) => {
		const unsubscribe = store.subscribe(update);
		return () => {
			unsubscribe();
		};
	});

	let show = state(true);
	let current = derived(() => {
		subscribe();
		return value;
	});

	let log = [];
	effect(() => {
		if ($.get(show)) {
			const val = $.get(current);
			log.push(val);
		}
	});

	flushSync();
	console.log('✓ Initial setup: effect value =', log[0]);

	// Hide - derived should be disconnected
	flushSync(() => set(show, false));
	console.log('✓ After hide: effect not reading derived');

	// Show again - derived should reconnect
	log = [];
	flushSync(() => set(show, true));
	console.log('✓ After show: effect reading derived again, value =', log[0]);

	// Update store - THIS IS THE KEY TEST!
	log = [];
	flushSync(() => store.set(1));

	if (log.length === 0 || log[0] !== 1) {
		console.error('✗ FAILED: Effect did not see updated value after reconnection!');
		console.error('  Expected: [1], Got:', log);
		test_passed = false;
	} else {
		console.log('✓ After store update: effect saw new value =', log[0]);
		console.log('\n✅ TEST PASSED! The bug is fixed.');
	}
});

pop();

if (!test_passed) {
	process.exit(1);
}
EOF
